INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (262, 156324, 12, 558, '自由人', '人生沧海茫茫，展转又来到一个春天，又开始重复着过去24年走过的脚印，又多踏出一只来。花开花落，年轮又画上了圆圈，人们又开始四处寻找自己的目标，随着年纪和记忆的增长而改变的改变，自己的信念还是死守着不变，永不更改，都市的生活让我们常常去放纵自己，而不会带自己一丝反醒的警钟，却是感觉到“明天会更美好”做在音箱旁边打开音乐，闭上眼睛感受着快感的音乐，希望时间能为此停留下来该多好，那怕一分，一秒，你也会感觉到幸福的。之后随着音乐的尽头而停止，留在脑海里的只回荡的音乐声，慢慢的消失，遗忘。。。。。。。。', '人生沧海茫茫，展转又来到一个春天，又开始重复着过去24年走过的脚印，又多踏出一只来。花开花落，年轮又画上了圆圈，人们又开始四处寻找自己的目标，随着年纪和记忆的增长而改变的改变，自己的信念还是死守着不变，永不更改，都市的生活让我们常常去放纵自己，而不会带自己一丝反醒的警钟，却是感觉到“明天会更美好”做在音箱旁边打开音乐，闭上眼睛感受着快感的音乐，希望时间能为此停留下来该多好，那怕一分，一秒，你也会感觉到幸福的。之后随着音乐的尽头而停止，留在脑海里的只回荡的音乐声，慢慢的消失，遗忘。。。。。。。。', NULL, '2002-04-01 19:23:00', 1, '20020419182921_bbsid_156324_board_12_d90121f633.html', '20020419182921');
